#include<bits/stdc++.h>
using namespace std;
int main() {
	int n, m, num, maxa, k = 0;
	bool b[11];
	cin >> n;
	for (int i = 0; i < n; i++) {
		cin >> m;
		num = 0;
		int a[100001]={0};
		for (int j = 0; j < m; j++) {
			cin >> a[j];

		}
		maxa = a[0];
		for (int j = m; j >= 0; j--) {
			maxa = max(maxa, a[j]);

		}
		for (int j = 0; j < m; j++) {
			if (maxa % a[j] == 0) {
				num++;

			}
		}
		if (num == m) {
				cout << "Yes" << endl;
		} else {
				cout << "No" << endl;
		}
	
	}
	return 0;
